1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	type QuoteResult = { premium: number };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	
9	const ITEM_BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const BLOCK_SIZE = 3;
19	const BLOCK_BASE_PREMIUM = 60;
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	const premiumFor = (totalBase: number): number =>
23	  totalBase + Math.ceil(totalBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
24	
25	const baseFor = (item: Item): number => ITEM_BASE_PREMIUMS[item.type];
26	
27	const groupByType = (items: Item[]): Map<string, Item[]> => {
28	  const groups = new Map<string, Item[]>();
29	  for (const item of items) {
30	    const group = groups.get(item.type) ?? [];
31	    group.push(item);
32	    groups.set(item.type, group);
33	  }
34	  return groups;
35	};
36	
37	const baseForGroup = (type: string, group: Item[]): number => {
38	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
39	  return group.reduce((sum, item) => sum + baseFor(item), 0);
40	};
41	
42	const totalBaseFor = (items: Item[]): number => {
43	  let total = 0;
44	  for (const [type, group] of groupByType(items)) {
45	    total += baseForGroup(type, group);
46	  }
47	  return total;
48	};
49	
50	const quoteFor = (step: QuoteStep): QuoteResult => ({
51	  premium: premiumFor(totalBaseFor(step.items)),
52	});
53	
54	export const processScenario = (input: Scenario): { results: QuoteResult[] } => {
55	  return { results: input.steps.map(quoteFor) };
56	};
57

