53	    const result = processScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
56	    });
57	    expect(result).toEqual({ results: [{ premium: 71 }] });
58	  });
59	  it("4 runes yield 100 G base premium (no block — block requires exactly 3) — total 115 G", () => {
60	    const result = processScenario({
61	      customer: { yearsWithMHPCO: 0 },
62	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
