101	  it.todo("sword with exactly enchantment 5 triggers high-enchantment surcharge");
102	  it.todo("sword with enchantment 4 does not trigger high-enchantment surcharge");
103	  it.todo("cursed sword with exactly enchantment 5 triggers both surcharges");
104	  it.todo("customer with exactly 2 years receives 20% loyalty discount");
105	  it.todo("each item in a quote is treated as first insurance (10% surcharge applies even on follow-up contracts)");
106	
107	  // ===== Modifier scope on multi-item policies =====
108	  it.todo("cursed sword + plain amulet — base 160 G + 50 G curse = 210 G before policy modifiers and fee");
109	
110	  // ===== Rounding (MHPCO's favor) =====
111	  it.todo("premium calculation yielding 197.5 G rounds up to 198 G");
112	  it.todo("payout calculation yielding 350.5 G rounds down to 350 G");
113	
114	  // ===== Integration: newcomer with cursed sword =====
115	  it.todo("newcomer (0 years), cursed sword (steel, ench 3) — premium 165 G");
116	
117	  // ===== Integration: long-standing customer's second contract =====
118	  it.todo("3-year customer's 2nd quote, cursed sword (steel, ench 7) — premium 160 G");
119	
