122	  it.todo("rune damage 200 G — payout 100 G (full minus deductible, no special clause)");
123	
124	  // ===== Claim processing: special clauses =====
125	  it.todo("dragon-material sword, ench 5, damage 800 G — payout 700 G (dragon full, then deductible)");
126	  it.todo("steel sword, ench 9, damage 1000 G — payout 400 G (50% then deductible)");
