134	  it.todo("policy covers 2 swords — insurance sum 2000 G, cap 4000 G");
135	  it.todo("dragon attack damages both swords (two sword damages) — each with own deductible");
136	  it.todo("claim with more damage entries of a type than insured — CLI exits non-zero");
137	
