139	  it.todo("policy with sword + amulet — insurance sum 1600 G, cap 3200 G");
140	  it.todo("cursed sword — cap stays at 2000 G (based on unmodified insurance value)");
141	  it.todo("policy with sword + 3 runes (block) — insurance sum 1750 G (block discount affects premium only)");
142	  it.todo("sword cap 2000 G, two successive 1500 G claims — payouts 1400 G then 600 G; remainingCap 600 then 0");
143	
